fun solve(nums: Array<Long>): Long {
    val n = nums.size
    if (n <= 1) return 0
    val maxVal = 1000000
    val isPrime = BooleanArray(maxVal + 1) { true }
    isPrime[0] = false
    isPrime[1] = false
    for (i in 2..maxVal) {
        if (isPrime[i]) {
            var j = i * 2
            while (j <= maxVal) {
                isPrime[j] = false
                j += i
            }
        }
    }
    val primesList = (2..maxVal).filter { isPrime[it] }

    val primesInArray = HashSet<Long>()
    for (x in nums) {
        if (x < 2) continue
        if (x <= maxVal && isPrime[x.toInt()]) {
            primesInArray.add(x)
        }
    }

    val primeToIndices = mutableMapOf<Long, MutableList<Int>>()
    for (j in nums.indices) {
        var temp = nums[j]
        if (temp == 1L) continue
        var k = 0
        while (k < primesList.size && primesList[k].toLong() * primesList[k] <= temp) {
            val p = primesList[k]
            if (temp % p == 0L) {
                val pLong = p.toLong()
                if (pLong in primesInArray) {
                    primeToIndices.getOrPut(pLong) { mutableListOf() }.add(j)
                }
                while (temp % p == 0L) {
                    temp /= p.toLong()
                }
            }
            k++
        }
        if (temp > 1) {
            if (temp in primesInArray) {
                primeToIndices.getOrPut(temp) { mutableListOf() }.add(j)
            }
        }
    }

    val dist = IntArray(n) { -1 }
    dist[0] = 0
    val queue = ArrayDeque<Int>()
    queue.add(0)

    while (queue.isNotEmpty()) {
        val i = queue.poll()
        if (i == n - 1) {
            return dist[i].toLong()
        }

        for (di in intArrayOf(-1, 1)) {
            val j = i + di
            if (j >= 0 && j < n && dist[j] == -1) {
                dist[j] = dist[i] + 1
                queue.add(j)
            }
        }

        if (nums[i] in primesInArray) {
            val p = nums[i]
            val list = primeToIndices.remove(p)
            if (list != null) {
                for (j in list) {
                    if (j == i) continue
                    if (dist[j] == -1) {
                        dist[j] = dist[i] + 1
                        queue.add(j)
                    }
                }
            }
        }
    }

    return -1
}
