                val jInt = j.toInt()
                if (spf[jInt] == jInt) {
                    spf[jInt] = i
                }
                isPrime[jInt] = false
                j += i
            }
        }
    }

    val primeToIndices = mutableMapOf<Int, MutableList<Int>>()
