        val num = nums[i].toInt()
        if (num < 2) continue
        var temp = num
        val set = mutableSetOf<Int>()
        while (temp > 1) {
            val p = spf[temp]
            set.add(p)
            while (temp % p == 0) {
                temp /= p
            }
        }
        for (p in set) {
            primeToIndices.getOrPut(p) { mutableListOf() }.add(i)
        }
    }

    val dist = IntArray(n) { -1 }
    val usedPrimes = BooleanArray(MAX_VAL + 1) { false }
    val queue: Queue<Int> = LinkedList()
    dist[0] = 0
    queue.add(0)

    while (queue.isNotEmpty()) {
        val i = queue.poll()
        if (i == n - 1) {
            return dist[i].toLong()
        }
        if (i - 1 >= 0 && dist[i - 1] == -1) {
            dist[i - 1] = dist[i] + 1
            queue.add(i - 1)
        }
        if (i + 1 < n && dist[i + 1] == -1) {
            dist[i + 1] = dist[i] + 1
            queue.add(i + 1)
        }
        val num = nums[i].toInt()
        if (num >= 2 && isPrime[num]) {
            val p = num
            if (!usedPrimes[p]) {
                usedPrimes[p] = true
                val list = primeToIndices.getOrDefault(p, listOf())
                for (j in list) {
                    if (j == i) continue
                    if (dist[j] == -1) {
                        dist[j] = dist[i] + 1
                        queue.add(j)
                    }
                }
            }
        }
    }
    return dist[n - 1].toLong()
}
