fun solve(nums: Array<Long>): Long {
    val n = nums.size
    if (n == 1) return 0

    val maxVal = 1000000
    val spf = IntArray(maxVal + 1) { it }
    val sqrtMax = Math.sqrt(maxVal.toDouble()).toInt()
    for (i in 2..sqrtMax) {
        if (spf[i] == i) {
            var j = i * i
            while (j <= maxVal) {
                if (spf[j] == j) {
                    spf[j] = i
                }
                j += i
            }
        }
    }

    val P = mutableSetOf<Long>()
    for (num in nums) {
        if (num > 1 && num <= maxVal) {
            val numInt = num.toInt()
            if (spf[numInt] == numInt) {
                P.add(num)
            }
        }
    }

    val primeToIndices = mutableMapOf<Long, MutableList<Int>>()
    for (i in nums.indices) {
        val num = nums[i]
        if (num == 1L) continue
        if (num > maxVal) continue
        var x = num.toInt()
        val distinctFactors = mutableSetOf<Int>()
        var temp = x
        while (temp > 1) {
            val p = spf[temp]
            distinctFactors.add(p)
            while (temp % p == 0) {
                temp /= p
            }
        }
        for (p in distinctFactors) {
            val pLong = p.toLong()
            if (pLong in P) {
                primeToIndices.getOrPut(pLong) { mutableListOf() }.add(i)
            }
        }
    }

    val dist = IntArray(n) { Int.MAX_VALUE }
    dist[0] = 0
    val queue = ArrayDeque<Int>()
    queue.add(0)

    while (queue.isNotEmpty()) {
        val i = queue.poll()
        if (i == n - 1) {
            return dist[i].toLong()
        }

        for (offset in listOf(-1, 1)) {
            val j = i + offset
            if (j in 0 until n && dist[j] > dist[i] + 1) {
                dist[j] = dist[i] + 1
                queue.add(j)
            }
        }

        val num = nums[i]
        if (num in P) {
            val list = primeToIndices[num]
            if (list != null) {
                for (j in list) {
                    if (j == i) continue
                    if (dist[j] > dist[i] + 1) {
                        dist[j] = dist[i] + 1
                        queue.add(j)
                    }
                }
            }
        }
    }

    return dist[n - 1].toLong()
}
